module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
    // Initialize counters
    always @(posedge CLK_in or negedge RST) begin
        if (!RST) begin
            count_n <= 3'b000;
            CLK_10 <= 1'b0;
            CLK_1 <= 1'b0;
        end else begin
            count_n <= count_n + 1;
            // CLK_10 generation
            if (count_n == 3'd4) begin
                CLK_10 <= ~CLK_10;
                count_n <= 3'd0;
            end
            // CLK_1 generation
            if (count_n == 3'd49) begin
                CLK_1 <= ~CLK_1;
                count_n <= 3'd0;
            end
        end
    end
    // CLK_50 generation
    always @(posedge CLK_in or negedge RST) begin
        if (!RST) begin
            CLK_50 <= 1'b0;
        end else begin
            CLK_50 <= ~CLK_50;
        end
    end
endmodule
